-- IEBC Register of Voters per polling station, aggregated from stream rows.
-- Source file supplied by product owner: rov_per_polling_station.pdf.

alter table public.polling_stations add column if not exists station_code text;
alter table public.polling_stations add column if not exists centre_code text;
alter table public.polling_stations add column if not exists centre_name text;
alter table public.polling_stations add column if not exists stream_count integer not null default 0;

create table if not exists public.kenya_polling_station_register (
  id bigserial primary key,
  county_code text not null,
  county_name text not null,
  constituency_code text not null,
  constituency_name text not null,
  ward_code text not null,
  ward_name text not null,
  centre_code text not null,
  centre_name text not null,
  polling_station_code text not null,
  polling_station_name text not null,
  stream_count integer not null default 1 check (stream_count > 0),
  registered_voters integer not null default 0 check (registered_voters >= 0),
  source_document text not null default 'IEBC Register of Voters per polling station',
  created_at timestamptz not null default now(),
  unique (county_code, constituency_code, ward_code, centre_code, polling_station_code)
);

alter table public.kenya_polling_station_register enable row level security;

drop policy if exists "authenticated users can read kenya polling station register" on public.kenya_polling_station_register;
create policy "authenticated users can read kenya polling station register" on public.kenya_polling_station_register
  for select to authenticated using (true);

grant select on public.kenya_polling_station_register to authenticated;

create index if not exists kenya_polling_register_county_idx on public.kenya_polling_station_register (county_name);
create index if not exists kenya_polling_register_constituency_idx on public.kenya_polling_station_register (constituency_name);
create index if not exists kenya_polling_register_ward_idx on public.kenya_polling_station_register (ward_name);
create index if not exists kenya_polling_register_station_idx on public.kenya_polling_station_register (polling_station_name);
create index if not exists polling_stations_station_code_idx on public.polling_stations (tenant_id, station_code);

on conflict (county_code, constituency_code, ward_code, centre_code, polling_station_code) do update set
  polling_station_name = excluded.polling_station_name,
  centre_name = excluded.centre_name,
  stream_count = excluded.stream_count,
  registered_voters = excluded.registered_voters;


create or replace function public.jukwaa_geo_key(value text)
returns text
language sql
immutable
as $$
  select regexp_replace(lower(coalesce(value, '')), '[^a-z0-9]+', '', 'g')
$$;

create or replace function public.sync_workspace_polling_stations(
  target_tenant uuid,
  target_position text default null,
  target_county text default null,
  target_constituency text default null,
  target_ward text default null
)
returns integer
language plpgsql
security definer
set search_path = public
as $$
declare
  country_row uuid;
  synced_count integer := 0;
begin
  if target_tenant is null then
    return 0;
  end if;

  values (target_tenant, 'Kenya', 'KE')
  on conflict (tenant_id, name) do update set code = excluded.code
  returning id into country_row;

  if country_row is null then
    select id into country_row from public.countries where tenant_id = target_tenant and code = 'KE' limit 1;
  end if;

  with scoped as (
    select *
    from public.kenya_polling_station_register r
    where (coalesce(target_county, '') = '' or public.jukwaa_geo_key(r.county_name) = public.jukwaa_geo_key(target_county))
      and (coalesce(target_constituency, '') = '' or public.jukwaa_geo_key(r.constituency_name) = public.jukwaa_geo_key(target_constituency))
      and (coalesce(target_ward, '') = '' or public.jukwaa_geo_key(r.ward_name) = public.jukwaa_geo_key(target_ward))
  )
  select distinct target_tenant, country_row, initcap(lower(county_name))
  from scoped
  on conflict (tenant_id, country_id, name) do nothing;

  with scoped as (
    select *
    from public.kenya_polling_station_register r
    where (coalesce(target_county, '') = '' or public.jukwaa_geo_key(r.county_name) = public.jukwaa_geo_key(target_county))
      and (coalesce(target_constituency, '') = '' or public.jukwaa_geo_key(r.constituency_name) = public.jukwaa_geo_key(target_constituency))
      and (coalesce(target_ward, '') = '' or public.jukwaa_geo_key(r.ward_name) = public.jukwaa_geo_key(target_ward))
  ), county_rows as (
    select c.id, public.jukwaa_geo_key(c.name) as key from public.counties c where c.tenant_id = target_tenant
  )
  select distinct target_tenant, c.id, initcap(lower(s.constituency_name))
  from scoped s
  join county_rows c on c.key = public.jukwaa_geo_key(s.county_name)
  on conflict (tenant_id, county_id, name) do nothing;

  with scoped as (
    select *
    from public.kenya_polling_station_register r
    where (coalesce(target_county, '') = '' or public.jukwaa_geo_key(r.county_name) = public.jukwaa_geo_key(target_county))
      and (coalesce(target_constituency, '') = '' or public.jukwaa_geo_key(r.constituency_name) = public.jukwaa_geo_key(target_constituency))
      and (coalesce(target_ward, '') = '' or public.jukwaa_geo_key(r.ward_name) = public.jukwaa_geo_key(target_ward))
  ), constituency_rows as (
    select c.id, public.jukwaa_geo_key(c.name) as key from public.constituencies c where c.tenant_id = target_tenant
  )
  select distinct target_tenant, c.id, initcap(lower(s.ward_name))
  from scoped s
  join constituency_rows c on c.key = public.jukwaa_geo_key(s.constituency_name)
  on conflict (tenant_id, constituency_id, name) do nothing;

  with scoped as (
    select *
    from public.kenya_polling_station_register r
    where (coalesce(target_county, '') = '' or public.jukwaa_geo_key(r.county_name) = public.jukwaa_geo_key(target_county))
      and (coalesce(target_constituency, '') = '' or public.jukwaa_geo_key(r.constituency_name) = public.jukwaa_geo_key(target_constituency))
      and (coalesce(target_ward, '') = '' or public.jukwaa_geo_key(r.ward_name) = public.jukwaa_geo_key(target_ward))
  ), ward_rows as (
    select w.id, public.jukwaa_geo_key(w.name) as key from public.wards w where w.tenant_id = target_tenant
  )
  select distinct target_tenant, w.id, 'Polling Stations'
  from scoped s
  join ward_rows w on w.key = public.jukwaa_geo_key(s.ward_name)
  on conflict (tenant_id, ward_id, name) do nothing;

  with scoped as (
    select *
    from public.kenya_polling_station_register r
    where (coalesce(target_county, '') = '' or public.jukwaa_geo_key(r.county_name) = public.jukwaa_geo_key(target_county))
      and (coalesce(target_constituency, '') = '' or public.jukwaa_geo_key(r.constituency_name) = public.jukwaa_geo_key(target_constituency))
      and (coalesce(target_ward, '') = '' or public.jukwaa_geo_key(r.ward_name) = public.jukwaa_geo_key(target_ward))
  ), station_rows as (
    select s.*, v.id as village_id
    from scoped s
    join public.wards w on w.tenant_id = target_tenant and public.jukwaa_geo_key(w.name) = public.jukwaa_geo_key(s.ward_name)
    join public.constituencies co on co.id = w.constituency_id and public.jukwaa_geo_key(co.name) = public.jukwaa_geo_key(s.constituency_name)
    join public.counties cn on cn.id = co.county_id and public.jukwaa_geo_key(cn.name) = public.jukwaa_geo_key(s.county_name)
    join public.villages v on v.tenant_id = target_tenant and v.ward_id = w.id and v.name = 'Polling Stations'
  )
  select
    target_tenant,
    village_id,
    station_name,
    sum(registered_voters)::integer,
    min(polling_station_code),
    min(centre_code),
    min(centre_name),
    sum(stream_count)::integer
  from (
    select
      village_id,
      initcap(lower(polling_station_name)) as station_name,
      registered_voters,
      polling_station_code,
      centre_code,
      initcap(lower(centre_name)) as centre_name,
      stream_count
    from station_rows
  ) deduped_stations
  group by village_id, station_name
  on conflict (tenant_id, village_id, name) do update set
    registered_voters = excluded.registered_voters,
    station_code = excluded.station_code,
    centre_code = excluded.centre_code,
    centre_name = excluded.centre_name,
    stream_count = excluded.stream_count;

  select count(*) into synced_count
  from public.kenya_polling_station_register r
  where (coalesce(target_county, '') = '' or public.jukwaa_geo_key(r.county_name) = public.jukwaa_geo_key(target_county))
    and (coalesce(target_constituency, '') = '' or public.jukwaa_geo_key(r.constituency_name) = public.jukwaa_geo_key(target_constituency))
    and (coalesce(target_ward, '') = '' or public.jukwaa_geo_key(r.ward_name) = public.jukwaa_geo_key(target_ward));

  return coalesce(synced_count, 0);
end;
$$;
